import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.println("Enter your name: ");

        String name = scanner.nextLine();

        // Limit the input length to prevent buffer overflow
        if (name.length() > 10) {
            System.out.println("Input exceeds maximum length of 10 characters. Exiting.");
            return;
        }

        // Create a buffer with size equal to input length
        char[] buffer = new char[name.length()];

        // Copy the user input into the buffer array
        for (int i = 0; i < name.length(); i++) {
            buffer[i] = name.charAt(i);
        }

        // Print out the content of the buffer array
        System.out.println("Buffer content: " + String.valueOf(buffer));
    }
}

